```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    // Connect to SQLite database
    auto conn = sqlgen::sqlite::connect("test_db.sqlite");

    // Define the Employee table
    auto employee_table = sqlgen::define_table<Employee>("Employee");

    // Create table aliases for the self-join
    auto e1 = employee_table.as("e1");
    auto e2 = employee_table.as("e2");

    // Build the LEFT JOIN query selecting employee and manager names
    auto query = sqlgen::select(e1.name.as("employee"), e2.name.as("manager"))
                    .from(e1)
                    .left_join(e2).on(e1.manager_id == e2.emp_id);

    // Execute the query and map results to EmployeeManager objects
    std::vector<EmployeeManager> results;
    for (auto row : conn.execute(query)) {
        results.push_back({row.employee, row.manager});
    }

    return results;
}

}
```

