  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    // Connect to the SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Define the Employee table
    auto Employee_table = sqlgen::table<Employee>("Employee");

    // Create table aliases for self-join (e1 for employee, e2 for manager)
    auto e1 = Employee_table.as("e1");
