# Complete Implementation

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::open("test_db.sqlite");

  std::vector<DepProj> results;

  // Perform RIGHT JOIN to include all projects
  // Some projects may not have associated departments (department_name will be NULL)
  auto query = sqlgen::select(
    sqlgen::column("d", "name"),
    sqlgen::column("p", "name")
  )
  .from(sqlgen::table<Department>().as("d"))
  .right_join(sqlgen::table<Project>().as("p"))
  .on(sqlgen::column("d", "department_id") == sqlgen::column("p", "department_id"));

  auto rows = db.execute(query);

  for (const auto& row : rows) {
    DepProj dp;
    // department_name is optional (can be NULL if no department matches)
    if (row[0].is_null()) {
      dp.department_name = std::nullopt;
    } else {
      dp.department_name = row[0].template get<std::string>();
    }
    // project_name is always present in RIGHT JOIN
    dp.project_name = row[1].template get<std::string>();
    results.push_back(dp);
  }

  return results;
}

}  // namespace right_join_departments_projects
```

**Key Implementation Details:**

1. **Database Connection**: Opens the SQLite database "test_db.sqlite" using `sqlgen::sqlite::open()`

2. **RIGHT JOIN Query**: Constructs a RIGHT JOIN query that includes all projects from the Project table, with optional matching departments from the Department table

3. **Result Mapping**: 
   - `department_name` is mapped to `std::optional<std::string>` since it can be NULL when a project has no matching department
   - `project_name` is always present (guaranteed by RIGHT JOIN including all projects)

4. **Return Value**: Returns a vector of `DepProj` structs containing the joined data

The RIGHT JOIN ensures all projects are included in the results, even if they don't have a corresponding department (in which case `department_name` will be `std::nullopt`).

