#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  // Connect to SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Create User table
  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS User (
      user_id INTEGER PRIMARY KEY,
      username VARCHAR(50) NOT NULL UNIQUE,
      email VARCHAR(100) NOT NULL UNIQUE,
      join_date DATETIME NOT NULL,
      city VARCHAR(50)
    )
  )");

  // Create Friendship table
  conn.execute(R"(
    CREATE TABLE IF NOT EXISTS Friendship (
      user_id1 INTEGER NOT NULL,
      user_id2 INTEGER NOT NULL,
      friendship_date DATETIME NOT NULL,
      PRIMARY KEY (user_id1, user_id2),
      FOREIGN KEY (user_id1) REFERENCES User(user_id),
      FOREIGN KEY (user_id2) REFERENCES User(user_id)
    )
  )");

  // Clear existing data for fresh analysis
  conn.execute("DELETE FROM Friendship");
  conn.execute("DELETE FROM User");

  // Insert users
  for (const auto& user : users) {
    auto stmt = conn.prepare(
      "INSERT INTO User (user_id, username, email, join_date, city) VALUES (?, ?, ?, ?, ?)"
    );
    stmt.bind(1, user.user_id.value);
    stmt.bind(2, user.username);
    stmt.bind(3, user.username + "@example.com");  // Generate email from username
    stmt.bind(4, "2024-01-01 00:00:00");  // Default join date
    stmt.bind(5, "DefaultCity");  // Default city
    stmt.execute();
  }

  // Insert friendships (bidirectional - insert both directions for symmetric relationships)
  for (const auto& friendship : friendships) {
    auto stmt = conn.prepare(
      "INSERT OR IGNORE INTO Friendship (user_id1, user_id2, friendship_date) VALUES (?, ?, ?)"
    );
    stmt.bind(1, friendship.user1_id);
    stmt.bind(2, friendship.user2_id);
    stmt.bind(3, friendship.created_at.value);
    stmt.execute();
  }

  std::vector<FriendConnection> results;

  // Query 1: SELF-JOIN to find mutual friends
  // Friends who share the same friend and are also friends with each other
  std::string mutual_friends_query = R"(
    SELECT DISTINCT u1.username as user1_name, u2.username as user2_name
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
      )
  )";

  auto mutual_result = conn.query(mutual_friends_query);
  while (mutual_result.next()) {
    FriendConnection fc;
    fc.user1_name = mutual_result.get<std::string>(0);
    fc.user2_name = mutual_result.get<std::string>(1);
    results.push_back(fc);
  }

  // Query 2: Nested query to find users with more than average friends
  std::string high_connection_query = R"(
    SELECT u.user_id, u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    HAVING friend_count > (
      SELECT AVG(friend_count) 
      FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user_id1)
    )
    ORDER BY friend_count DESC
  )";

  conn.query(high_connection_query);  // Execute for analysis

  // Query 3: Friend-of-friend relationships (exactly one mutual friend apart)
  std::string fof_query = R"(
    SELECT DISTINCT u1.username, u2.username
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u2 ON f2.user_id2 = u2.user_id
    WHERE u1.user_id < u2.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3 
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u2.user_id
      )
  )";

  auto fof_result = conn.query(fof_query);
  while (fof_result.next()) {
    FriendConnection fc;
    fc.user1_name = fof_result.get<std::string>(0);
    fc.user2_name = fof_result.get<std::string>(1);
    results.push_back(fc);
  }

  // Query 4: Count friends per user and identify most connected users
  std::string friend_count_query = R"(
    SELECT u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
  )";

  conn.query(friend_count_query);  // Execute for analysis

  // Query 5: Find users in same city who aren't friends (recommendation)
  std::string recommendation_query = R"(
    SELECT u1.username, u2.username
    FROM User u1
    CROSS JOIN User u2
    WHERE u1.user_id < u2.user_id
      AND u1.city = u2.city
      AND u1.city IS NOT NULL
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f 
        WHERE f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id
      )
  )";

  auto rec_result = conn.query(recommendation_query);
  while (rec_result.next()) {
    FriendConnection fc;
    fc.user1_name = rec_result.get<std::string>(0);
    fc.user2_name = rec_result.get<std::string>(1);
    results.push_back(fc);
  }

  return results;
}

}  // namespace analyze_social_network

