      select_from<Supplier, "s">(col<"name", "s"> | as<"supplier_name">,
                                 col<"name", "p"> | as<"product_name">) |
      left_join<Product, "p">(col<"supplier_id", "s"> == col<"supplier_id", "p">) |
      to<std::vector<SupProd>>;
  return query(conn).value();
}

