  for (const auto& row : query_result) {
    SupProd sp;
    sp.supplier_name = row.template get<std::string>(0);

    // Handle optional product_name
    auto product_name_val = row.template get<std::string>(1);
    if (!product_name_val.empty() || !row.is_null(1)) {
      sp.product_name = product_name_val;
    } else {
      sp.product_name = std::nullopt;
