/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Connect to SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Create Department table
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS Department (
      department_id INTEGER PRIMARY KEY,
      department_name VARCHAR(100) NOT NULL,
      location VARCHAR(100)
    )
  )");

  // Create Employee table
  db.execute(R"(
    CREATE TABLE IF NOT EXISTS Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name VARCHAR(100) NOT NULL,
      last_name VARCHAR(100) NOT NULL,
      salary REAL
    )
  )");

  // Insert Department data
  for (const auto& dept : depts) {
    db.execute("INSERT INTO Department VALUES (?, ?, ?)", 
               dept.department_id, dept.department_name, dept.location);
  }

  // Insert Employee data
  for (const auto& emp : emps) {
    db.execute("INSERT INTO Employee VALUES (?, ?, ?, ?, ?)",
               emp.employee_id, emp.department_id, emp.first_name, emp.last_name, emp.salary);
  }

  JoinAnalysis results;

  // INNER JOIN
  auto inner_rows = db.query(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    INNER JOIN Employee e ON d.department_id = e.department_id
  )");
  for (const auto& row : inner_rows) {
    results.inner_join_results.push_back({row[0], row[1], row[2], row[3]});
  }

  // LEFT JOIN
  auto left_rows = db.query(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
  )");
  for (const auto& row : left_rows) {
    results.left_join_results.push_back({row[0], row[1], row[2], row[3]});
  }

  // RIGHT JOIN (simulated with LEFT JOIN reversed)
  auto right_rows = db.query(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON d.department_id = e.department_id
  )");
  for (const auto& row : right_rows) {
    results.right_join_results.push_back({row[0], row[1], row[2], row[3]});
  }

  // FULL OUTER JOIN (simulated with UNION)
  auto full_rows = db.query(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    LEFT JOIN Employee e ON d.department_id = e.department_id
    UNION
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Employee e
    LEFT JOIN Department d ON d.department_id = e.department_id
    WHERE d.department_id IS NULL
  )");
  for (const auto& row : full_rows) {
    results.full_join_results.push_back({row[0], row[1], row[2], row[3]});
  }

  return results;
}

} // namespace analyze_department_employees
