std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::connect("test_db.sqlite");

  // Define table instances
  sqlgen::Table<Product> product("Product");
  sqlgen::Table<Sales> sales("Sales");

  // Define the aggregation for total sales (price * quantity)
  auto total_sales = sqlgen::sum(product.price * sales.quantity);

  // Build the query
  auto query = sqlgen::select(
    product.product_id,
    product.product_name,
    product.category,
    total_sales.as("total_sales")
  )
  .from(product)
